-- SECCION NUEVA - SEGURIDAD Y CRUD COMPLETO | Agregado para el Proyecto Integrador Python. | Incluye logins, usuarios, permisos y SPs CRUD para todas | las tablas de la base de datos SonoraInc.


-- PASO 1 - LOGINS EN EL SERVIDOR | Ejecutar conectado como sa o Windows Auth (sysadmin)

USE master;
GO

-- Login administrador: puede crear y modificar objetos en SonoraInc
IF NOT EXISTS (SELECT 1 FROM sys.server_principals WHERE name = 'SonoraAdmin')
BEGIN
    CREATE LOGIN SonoraAdmin
        WITH PASSWORD    = 'Admin@Sonora2026',
             CHECK_POLICY = ON;
END;
GO

-- Login de aplicacion: solo puede ejecutar SPs, lo usa Python para conectarse
IF NOT EXISTS (SELECT 1 FROM sys.server_principals WHERE name = 'SonoraApp')
BEGIN
    CREATE LOGIN SonoraApp
        WITH PASSWORD    = 'App@Sonora2026',
             CHECK_POLICY = ON;
END;
GO


-- PASO 2 - USUARIOS Y PERMISOS EN LA BASE DE DATOS

USE SonoraInc;
GO

IF NOT EXISTS (SELECT 1 FROM sys.database_principals WHERE name = 'SonoraAdmin')
    CREATE USER SonoraAdmin FOR LOGIN SonoraAdmin;
GO

IF NOT EXISTS (SELECT 1 FROM sys.database_principals WHERE name = 'SonoraApp')
    CREATE USER SonoraApp FOR LOGIN SonoraApp;
GO

-- SonoraAdmin recibe db_owner para poder crear y modificar objetos
ALTER ROLE db_owner ADD MEMBER SonoraAdmin;
GO

-- SonoraApp solo puede ejecutar procedimientos del esquema Procesos
GRANT EXECUTE ON SCHEMA::Procesos TO SonoraApp;
GO


-- PASO 3 - CRUD Catalogo.Artista | (tabla elegida para el proyecto integrador Python)

CREATE PROCEDURE Procesos.sp_InsertarArtista
    @nombreArtista           VARCHAR(50),
    @paisOrigenArtista       VARCHAR(50),
    @descripcionArtista      VARCHAR(50) = NULL,
    @Productora_idProductora INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Productora WHERE idProductora = @Productora_idProductora)
        THROW 50101, 'La productora especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Artista WHERE nombreArtista = @nombreArtista)
        THROW 50107, 'Ya existe un artista con ese nombre.', 1;
    DECLARE @idArtista INT;
    SELECT @idArtista = ISNULL(MAX(idArtista), 0) + 1 FROM Catalogo.Artista;
    VALUES (@idArtista, @nombreArtista, @paisOrigenArtista, @descripcionArtista, @Productora_idProductora);
    SELECT 'Artista registrado correctamente' AS Mensaje, @idArtista AS idArtista;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarArtistas
    @idArtista INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT a.idArtista, a.nombreArtista, a.paisOrigenArtista,
           ISNULL(a.descripcionArtista, '-') AS descripcionArtista,
           p.idProductora, p.nombreProductora
    FROM Catalogo.Artista a
    INNER JOIN Catalogo.Productora p ON a.Productora_idProductora = p.idProductora
    WHERE (@idArtista IS NULL OR a.idArtista = @idArtista);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarArtista
    @idArtista               INT,
    @nombreArtista           VARCHAR(50),
    @paisOrigenArtista       VARCHAR(50),
    @descripcionArtista      VARCHAR(50) = NULL,
    @Productora_idProductora INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Artista WHERE idArtista = @idArtista)
        THROW 50102, 'El artista especificado no existe.', 1;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Productora WHERE idProductora = @Productora_idProductora)
        THROW 50103, 'La productora especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Artista WHERE nombreArtista = @nombreArtista AND idArtista != @idArtista)
        THROW 50108, 'Ya existe otro artista con ese nombre.', 1;
    UPDATE Catalogo.Artista
    SET nombreArtista = @nombreArtista, paisOrigenArtista = @paisOrigenArtista,
        descripcionArtista = @descripcionArtista, Productora_idProductora = @Productora_idProductora
    WHERE idArtista = @idArtista;
    SELECT 'Artista actualizado correctamente' AS Mensaje;
END;
GO

CREATE OR ALTER PROCEDURE Procesos.sp_EliminarArtista
    @idArtista INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Artista WHERE idArtista = @idArtista)
        THROW 50104, 'El artista especificado no existe.', 1;
    DELETE FROM Interaccion.ArtistaCancion WHERE Artista_idArtista = @idArtista;
    DELETE FROM Interaccion.UsuarioArtista  WHERE Artista_idArtista = @idArtista;
    DELETE FROM Catalogo.Artista            WHERE idArtista         = @idArtista;
    SELECT 'Artista eliminado correctamente' AS Mensaje;
END;
GO


-- PASO 4 - CRUD Catalogo.Genero

CREATE PROCEDURE Procesos.sp_InsertarGenero
    @nombreGenero VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF EXISTS (SELECT 1 FROM Catalogo.Genero WHERE nombreGenero = @nombreGenero)
        THROW 50201, 'Ya existe un genero con ese nombre.', 1;
    DECLARE @idGenero INT;
    SELECT @idGenero = ISNULL(MAX(idGenero), 0) + 1 FROM Catalogo.Genero;
    SELECT 'Genero registrado correctamente' AS Mensaje, @idGenero AS idGenero;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarGeneros
    @idGenero INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT idGenero, nombreGenero FROM Catalogo.Genero
    WHERE (@idGenero IS NULL OR idGenero = @idGenero);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarGenero
    @idGenero     INT,
    @nombreGenero VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @idGenero)
        THROW 50202, 'El genero especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Genero WHERE nombreGenero = @nombreGenero AND idGenero != @idGenero)
        THROW 50203, 'Ya existe otro genero con ese nombre.', 1;
    UPDATE Catalogo.Genero SET nombreGenero = @nombreGenero WHERE idGenero = @idGenero;
    SELECT 'Genero actualizado correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarGenero
    @idGenero INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @idGenero)
        THROW 50204, 'El genero especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE Genero_idGenero = @idGenero)
        THROW 50205, 'No se puede eliminar: el genero tiene canciones asociadas.', 1;
    DELETE FROM Catalogo.Genero WHERE idGenero = @idGenero;
    SELECT 'Genero eliminado correctamente' AS Mensaje;
END;
GO


-- PASO 5 - CRUD Catalogo.Album

CREATE PROCEDURE Procesos.sp_InsertarAlbum
    @tituloAlbum           VARCHAR(50),
    @fechaLanzamientoAlbum DATE
AS
BEGIN
    SET NOCOUNT ON;
    IF EXISTS (SELECT 1 FROM Catalogo.Album WHERE tituloAlbum = @tituloAlbum)
        THROW 50209, 'Ya existe un album con ese titulo.', 1;
    DECLARE @idAlbum INT;
    SELECT @idAlbum = ISNULL(MAX(idAlbum), 0) + 1 FROM Catalogo.Album;
    VALUES (@idAlbum, @tituloAlbum, @fechaLanzamientoAlbum);
    SELECT 'Album registrado correctamente' AS Mensaje, @idAlbum AS idAlbum;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarAlbumes
    @idAlbum INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT idAlbum, tituloAlbum, fechaLanzamientoAlbum FROM Catalogo.Album
    WHERE (@idAlbum IS NULL OR idAlbum = @idAlbum);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarAlbum
    @idAlbum               INT,
    @tituloAlbum           VARCHAR(50),
    @fechaLanzamientoAlbum DATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @idAlbum)
        THROW 50206, 'El album especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Album WHERE tituloAlbum = @tituloAlbum AND idAlbum != @idAlbum)
        THROW 50210, 'Ya existe otro album con ese titulo.', 1;
    UPDATE Catalogo.Album
    SET tituloAlbum = @tituloAlbum, fechaLanzamientoAlbum = @fechaLanzamientoAlbum
    WHERE idAlbum = @idAlbum;
    SELECT 'Album actualizado correctamente' AS Mensaje;
END;
GO

CREATE OR ALTER PROCEDURE Procesos.sp_EliminarAlbum
    @idAlbum INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @idAlbum)
        THROW 50207, 'El album especificado no existe.', 1;
    UPDATE Catalogo.Cancion SET Album_idAlbum = NULL WHERE Album_idAlbum = @idAlbum;
    DELETE FROM Catalogo.Album WHERE idAlbum = @idAlbum;
    SELECT 'Album eliminado correctamente' AS Mensaje;
END;
GO


-- PASO 6 - CRUD Catalogo.Productora

CREATE PROCEDURE Procesos.sp_InsertarProductora
    @nombreProductora VARCHAR(50),
    @paisProductora   VARCHAR(50),
    @correoProductora VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF EXISTS (SELECT 1 FROM Catalogo.Productora WHERE nombreProductora = @nombreProductora)
        THROW 50216, 'Ya existe una productora con ese nombre.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Productora WHERE correoProductora = @correoProductora)
        THROW 50211, 'Ya existe una productora con ese correo.', 1;
    DECLARE @idProductora INT;
    SELECT @idProductora = ISNULL(MAX(idProductora), 0) + 1 FROM Catalogo.Productora;
    VALUES (@idProductora, @nombreProductora, @paisProductora, @correoProductora);
    SELECT 'Productora registrada correctamente' AS Mensaje, @idProductora AS idProductora;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarProductoras
    @idProductora INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT idProductora, nombreProductora, paisProductora, correoProductora
    FROM Catalogo.Productora
    WHERE (@idProductora IS NULL OR idProductora = @idProductora);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarProductora
    @idProductora     INT,
    @nombreProductora VARCHAR(50),
    @paisProductora   VARCHAR(50),
    @correoProductora VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Productora WHERE idProductora = @idProductora)
        THROW 50212, 'La productora especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Productora WHERE nombreProductora = @nombreProductora AND idProductora != @idProductora)
        THROW 50217, 'Ya existe otra productora con ese nombre.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Productora WHERE correoProductora = @correoProductora AND idProductora != @idProductora)
        THROW 50213, 'Ya existe otra productora con ese correo.', 1;
    UPDATE Catalogo.Productora
    SET nombreProductora = @nombreProductora, paisProductora = @paisProductora, correoProductora = @correoProductora
    WHERE idProductora = @idProductora;
    SELECT 'Productora actualizada correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarProductora
    @idProductora INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Productora WHERE idProductora = @idProductora)
        THROW 50214, 'La productora especificada no existe.', 1;
    DECLARE @artistas TABLE (idArtista INT);
    DELETE FROM Interaccion.ArtistaCancion WHERE Artista_idArtista IN (SELECT idArtista FROM @artistas);
    DELETE FROM Interaccion.UsuarioArtista  WHERE Artista_idArtista IN (SELECT idArtista FROM @artistas);
    DELETE FROM Catalogo.Artista            WHERE Productora_idProductora = @idProductora;
    DELETE FROM Catalogo.Productora WHERE idProductora = @idProductora;
    SELECT 'Productora eliminada correctamente' AS Mensaje;
END;
GO


-- PASO 7 - CRUD Catalogo.Cancion

CREATE PROCEDURE Procesos.sp_InsertarCancion
    @tituloCancion   VARCHAR(50),
    @duracionCancion FLOAT,
    @idiomaCancion   VARCHAR(50) = NULL,
    @Genero_idGenero INT,
    @Album_idAlbum   INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @Genero_idGenero)
        THROW 50218, 'El genero especificado no existe.', 1;
    IF @Album_idAlbum IS NOT NULL AND NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @Album_idAlbum)
        THROW 50219, 'El album especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE tituloCancion = @tituloCancion AND Genero_idGenero = @Genero_idGenero)
        THROW 50220, 'Ya existe una cancion con ese titulo en el mismo genero.', 1;
    DECLARE @idCancion INT;
    SELECT @idCancion = ISNULL(MAX(idCancion), 0) + 1 FROM Catalogo.Cancion;
    VALUES (@idCancion, @tituloCancion, @duracionCancion, @idiomaCancion, @Genero_idGenero, @Album_idAlbum);
    SELECT 'Cancion registrada correctamente' AS Mensaje, @idCancion AS idCancion;
END;
GO

CREATE OR ALTER PROCEDURE Procesos.sp_ConsultarCanciones
    @idCancion INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT c.idCancion, c.tituloCancion, c.duracionCancion,
           ISNULL(c.idiomaCancion, '-') AS idiomaCancion,
           g.nombreGenero,
           c.Album_idAlbum,
           a.tituloAlbum,
           ar.idArtista,
           ar.nombreArtista
    FROM Catalogo.Cancion c
    INNER JOIN Catalogo.Genero g ON c.Genero_idGenero = g.idGenero
    LEFT  JOIN Catalogo.Album  a ON c.Album_idAlbum   = a.idAlbum
    OUTER APPLY (
        SELECT TOP 1 art.idArtista, art.nombreArtista
        FROM Interaccion.ArtistaCancion ac
        JOIN Catalogo.Artista art ON ac.Artista_idArtista = art.idArtista
        WHERE ac.Cancion_idCancion = c.idCancion
        ORDER BY art.idArtista
    ) ar
    WHERE (@idCancion IS NULL OR c.idCancion = @idCancion);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarCancion
    @idCancion       INT,
    @tituloCancion   VARCHAR(50),
    @duracionCancion FLOAT,
    @idiomaCancion   VARCHAR(50) = NULL,
    @Genero_idGenero INT,
    @Album_idAlbum   INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE idCancion = @idCancion)
        THROW 50221, 'La cancion especificada no existe.', 1;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @Genero_idGenero)
        THROW 50222, 'El genero especificado no existe.', 1;
    IF @Album_idAlbum IS NOT NULL AND NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @Album_idAlbum)
        THROW 50223, 'El album especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE tituloCancion = @tituloCancion AND Genero_idGenero = @Genero_idGenero AND idCancion != @idCancion)
        THROW 50224, 'Ya existe otra cancion con ese titulo en el mismo genero.', 1;
    UPDATE Catalogo.Cancion
    SET tituloCancion = @tituloCancion, duracionCancion = @duracionCancion,
        idiomaCancion = @idiomaCancion, Genero_idGenero = @Genero_idGenero, Album_idAlbum = @Album_idAlbum
    WHERE idCancion = @idCancion;
    SELECT 'Cancion actualizada correctamente' AS Mensaje;
END;
GO

CREATE OR ALTER PROCEDURE Procesos.sp_EliminarCancion
    @idCancion INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE idCancion = @idCancion)
        THROW 50221, 'La cancion especificada no existe.', 1;
    DELETE FROM Interaccion.ArtistaCancion  WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Interaccion.CancionPlaylist WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Interaccion.UsuarioCancion  WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Interaccion.Reproduccion    WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Finanzas.Regalia            WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Catalogo.Cancion            WHERE idCancion         = @idCancion;
    SELECT 'Cancion eliminada correctamente' AS Mensaje;
END;
GO


-- PASO 8 - CRUD complementario Seguridad.Usuario | (sp_RegistrarUsuario e sp_IniciarSesion ya existen)

CREATE PROCEDURE Procesos.sp_ConsultarUsuarios
    @idUsuario INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT idUsuario, nombreUsuario, apellidoUsuario,
           ISNULL(segundoNombreUsuario, '-')   AS segundoNombreUsuario,
           ISNULL(segundoApellidoUsuario, '-') AS segundoApellidoUsuario,
           correoUsuario, fechaRegistroUsuario
    FROM Seguridad.Usuario
    WHERE (@idUsuario IS NULL OR idUsuario = @idUsuario);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarUsuario
    @idUsuario               INT,
    @nombreUsuario           VARCHAR(50),
    @apellidoUsuario         VARCHAR(50),
    @segundoNombreUsuario    VARCHAR(50) = NULL,
    @segundoApellidoUsuario  VARCHAR(50) = NULL,
    @correoUsuario           VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE idUsuario = @idUsuario)
        THROW 50223, 'El usuario especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE correoUsuario = @correoUsuario AND idUsuario != @idUsuario)
        THROW 50224, 'El correo ya esta en uso por otro usuario.', 1;
    UPDATE Seguridad.Usuario
    SET nombreUsuario = @nombreUsuario, apellidoUsuario = @apellidoUsuario,
        segundoNombreUsuario = @segundoNombreUsuario, segundoApellidoUsuario = @segundoApellidoUsuario,
        correoUsuario = @correoUsuario
    WHERE idUsuario = @idUsuario;
    SELECT 'Usuario actualizado correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarUsuario
    @idUsuario INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE idUsuario = @idUsuario)
        THROW 50225, 'El usuario especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Finanzas.Suscripcion WHERE Usuario_idUsuario = @idUsuario)
        THROW 50226, 'No se puede eliminar: el usuario tiene suscripciones activas.', 1;
    DELETE FROM Interaccion.UsuarioCancion  WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.UsuarioArtista  WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.Reproduccion    WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.Playlist        WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Seguridad.Usuario           WHERE idUsuario         = @idUsuario;
    SELECT 'Usuario eliminado correctamente' AS Mensaje;
END;
GO


