CREATE PROCEDURE Procesos.sp_ActualizarPlaylist
    @idPlaylist          INT,
    @nombrePlaylist      VARCHAR(50),
    @privacidadPlaylist  VARCHAR(50),
    @descripcionPlaylist VARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Interaccion.Playlist WHERE idPlaylist = @idPlaylist)
        THROW 50228, 'La playlist especificada no existe.', 1;
    IF @privacidadPlaylist NOT IN ('Privada', 'Publica')
        THROW 50229, 'La privacidad debe ser Privada o Publica.', 1;
    UPDATE Interaccion.Playlist
