CREATE PROCEDURE Procesos.sp_ConsultarSuscripciones
    @idSuscripcion INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT s.idSuscripcion, s.tipoPlanSuscripcion, s.fechaInicioSuscripcion,
           s.fechaFinSuscripcion, ISNULL(s.estadoSuscripcion, '-') AS estadoSuscripcion,
           u.nombreUsuario, u.apellidoUsuario
    FROM Finanzas.Suscripcion  s
    INNER JOIN Seguridad.Usuario u ON s.Usuario_idUsuario = u.idUsuario
    WHERE (@idSuscripcion IS NULL OR s.idSuscripcion = @idSuscripcion);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarSuscripcion
    @idSuscripcion       INT,
    @tipoPlanSuscripcion VARCHAR(50),
    @fechaFinSuscripcion DATE = NULL,
    @estadoSuscripcion   VARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Finanzas.Suscripcion WHERE idSuscripcion = @idSuscripcion)
        THROW 50233, 'La suscripcion especificada no existe.', 1;
    IF @tipoPlanSuscripcion NOT IN ('Gratis', 'Premium')
        THROW 50234, 'El tipo de plan debe ser Gratis o Premium.', 1;
    IF @estadoSuscripcion IS NOT NULL AND @estadoSuscripcion NOT IN ('Activa', 'Cancelada', 'Vencida')
        THROW 50235, 'El estado debe ser Activa, Cancelada o Vencida.', 1;
    UPDATE Finanzas.Suscripcion
    SET tipoPlanSuscripcion = @tipoPlanSuscripcion,
        fechaFinSuscripcion = @fechaFinSuscripcion,
        estadoSuscripcion   = @estadoSuscripcion
    WHERE idSuscripcion = @idSuscripcion;
    SELECT 'Suscripcion actualizada correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarSuscripcion
    @idSuscripcion INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Finanzas.Suscripcion WHERE idSuscripcion = @idSuscripcion)
        THROW 50236, 'La suscripcion especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Finanzas.Pago WHERE Suscripcion_idSuscripcion = @idSuscripcion)
        THROW 50237, 'No se puede eliminar: la suscripcion tiene pagos registrados.', 1;
    DELETE FROM Finanzas.Suscripcion WHERE idSuscripcion = @idSuscripcion;
    SELECT 'Suscripcion eliminada correctamente' AS Mensaje;
END;
GO


