-- PASO 14 - CRUD Interaccion.ArtistaCancion (tabla sin SPs)

CREATE PROCEDURE Procesos.sp_InsertarArtistaCancion
    @Artista_idArtista INT,
    @Cancion_idCancion INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Artista WHERE idArtista = @Artista_idArtista)
        THROW 50253, 'El artista especificado no existe.', 1;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE idCancion = @Cancion_idCancion)
        THROW 50254, 'La cancion especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Interaccion.ArtistaCancion WHERE Artista_idArtista = @Artista_idArtista AND Cancion_idCancion = @Cancion_idCancion)
        THROW 50255, 'El artista ya esta asociado a esa cancion.', 1;
    VALUES (@Artista_idArtista, @Cancion_idCancion);
    SELECT 'Artista asociado a cancion correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarArtistaCancion
    @Artista_idArtista INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT a.idArtista, a.nombreArtista, c.idCancion, c.tituloCancion
    FROM Interaccion.ArtistaCancion ac
    INNER JOIN Catalogo.Artista a ON ac.Artista_idArtista = a.idArtista
    INNER JOIN Catalogo.Cancion c ON ac.Cancion_idCancion = c.idCancion
    WHERE (@Artista_idArtista IS NULL OR ac.Artista_idArtista = @Artista_idArtista);
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarArtistaCancion
    @Artista_idArtista INT,
    @Cancion_idCancion INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Interaccion.ArtistaCancion WHERE Artista_idArtista = @Artista_idArtista AND Cancion_idCancion = @Cancion_idCancion)
        THROW 50256, 'La asociacion artista-cancion no existe.', 1;
    DELETE FROM Interaccion.ArtistaCancion
    WHERE Artista_idArtista = @Artista_idArtista AND Cancion_idCancion = @Cancion_idCancion;
    SELECT 'Asociacion artista-cancion eliminada correctamente' AS Mensaje;
END;
GO


-- PASO 15 - SELECT y DELETE complementarios para tablas | junction que ya tienen INSERT via SPs existentes | (CancionPlaylist, UsuarioCancion, UsuarioArtista)

CREATE PROCEDURE Procesos.sp_ConsultarCancionPlaylist
    @Playlist_idPlaylist INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT pl.idPlaylist, pl.nombrePlaylist, c.idCancion, c.tituloCancion
    FROM Interaccion.CancionPlaylist cp
    INNER JOIN Interaccion.Playlist  pl ON cp.Playlist_idPlaylist = pl.idPlaylist
