-- Columna passwordHash existe en Usuario
SELECT
    CASE WHEN COUNT(*) = 1 THEN 'OK — passwordHash existe'
         ELSE 'ERROR — columna no encontrada' END AS Gap1_passwordHash
FROM INFORMATION_SCHEMA.COLUMNS
WHERE TABLE_SCHEMA = 'Seguridad'
